// Click Load More repeatedly until all faculty are loaded
async function loadAll() {
  let prevCount = 0;
  let maxAttempts = 80; // safety limit
  while (maxAttempts-- > 0) {
    const wrapper = document.querySelector('.views-infinite-scroll-content-wrapper');
    const cols = wrapper ? wrapper.querySelectorAll('[class*="col-"]').length : 0;
    if (cols === prevCount && prevCount > 0) break; // no new results
    prevCount = cols;

    const loadMore = [...document.querySelectorAll('a.button, a[class*="button"]')].find(a => a.textContent.includes('Load More'));
    if (!loadMore) break;

    loadMore.click();
    await new Promise(r => setTimeout(r, 1500)); // wait for AJAX
  }
  const wrapper = document.querySelector('.views-infinite-scroll-content-wrapper');
  const finalCols = wrapper ? wrapper.querySelectorAll('[class*="col-"]').length : 0;
  return `Done. Total col elements: ${finalCols}, approx faculty: ${Math.floor(finalCols/3)}`;
}
